+                    entryBlock.add(normalizedTry.apply(entryBlock));
+                } else {
+                    CatchBuilder catchBuilder = try_(entryBlock.parentBody(), tryB -> {
+                        tryB.add(normalizedTry.apply(tryB));
+                        tryB.add(core_yield());
