+                    entryBlock.add(finallyBody == null
+                            ? catchBuilder.noFinalizer()
+                            : catchBuilder.finally_(finB ->
+                                    finB.transformBody(finallyBody, List.of(), entryBlock.context(), CodeTransformer.COPYING_TRANSFORMER)));
